let data = $input.item.json.actions;

// Inicializa um objeto para armazenar o resultado final
let resultObject = { ...$input.item.json };

// Faz o loop sobre cada uma das propriedades
for (let i in data) {
    // Pega a propriedade atual, o seu "action" e o seu "value"
    let dataItem = data[i];
    let action = dataItem.action_type;
    let value = dataItem.value;

    // Adiciona uma nova propriedade no objeto resultante com o action_type como chave e o value como valor
    resultObject[action] = value;
}

// Remova o array de ações original para evitar duplicação (opcional)
delete resultObject.actions;

// Retorna o objeto JSON processado com todas as colunas
return resultObject;

