// Pega os dados do JSON
let data = $node["Aggregate"].json["data"];

// Mapeia os status das contas
const accountStatusMap = {
    1: "ACTIVE",
    2: "DISABLED",
    3: "UNSETTLED",
    7: "PENDING_RISK_REVIEW",
    8: "PENDING_SETTLEMENT",
    9: "IN_GRACE_PERIOD",
    100: "PENDING_CLOSURE",
    101: "CLOSED",
    201: "ANY_ACTIVE",
    202: "ANY_CLOSED"
};

let reports = [];

for (let i = 0; i < data.length; i++) {
    const row = data[i];
    const accountName = row.name;
    const accountId   = row.account_id;
    const dateStart   = row.date_start || "";
    const dateStop    = row.date_stop  || "";

    // parse de gastos
    const spend        = row.spend ? parseFloat(row.spend) : 0;
    const spendFormatted = spend.toFixed(2).replace('.', ',');

    // métricas básicas
    const impressions = row.impressions ? parseInt(row.impressions).toLocaleString('pt-BR') : '0';
    const reach       = row.reach       ? parseInt(row.reach).toLocaleString('pt-BR')       : '0';
    const clicks      = row.clicks      ? parseInt(row.clicks).toLocaleString('pt-BR')      : '0';
    const ctr         = row.impressions
                        ? ((row.clicks / row.impressions) * 100)
                            .toFixed(2).replace('.', ',')
                        : '0,00';
    const cpm         = row.impressions
                        ? ((spend / parseInt(row.impressions)) * 1000)
                            .toFixed(2).replace('.', ',')
                        : '0,00';

    // leads e custo por lead
    const lead        = row.lead ? parseInt(row.lead).toLocaleString('pt-BR') : '0';
    const custo_lead  = row.lead
                        ? (spend / parseInt(row.lead))
                            .toFixed(2).replace('.', ',')
                        : '0,00';

    // compras e custo por compra
    const purchase       = row.purchase ? parseInt(row.purchase).toLocaleString('pt-BR') : '0';
    const custo_purchase = row.purchase
                           ? (spend / parseInt(row.purchase))
                               .toFixed(2).replace('.', ',')
                           : '0,00';

    // saldo restante em contas pré-pagas
    let saldo_restante = '';
    if (row.is_prepay_account) {
      const cap  = parseFloat(row.spend_cap);
      const spent= parseFloat(row.amount_spent);
      // dividindo por 100 se for centavos; ajuste conforme sua lógica de dados
      const rest = ((cap - spent) / 100).toFixed(2).replace('.', ',');
      saldo_restante = rest;
    }

    // moeda
    let currency = row.currency;
    switch (currency) {
      case 'EUR': currency = '€';  break;
      case 'BRL': currency = 'R$'; break;
      case 'USD': currency = '$';  break;
      default:    /* deixa como veio */ break;
    }

    // status e emoji
    const status = accountStatusMap[row.account_status] || "UNKNOWN";
    let emoji;
    if (status !== "ACTIVE")     emoji = "❌";
    else if (spend > 0)          emoji = "🟢";
    else                          emoji = "🟡";

    // monta o report
    let report = `${emoji} ${accountName} - ${currency} ${spendFormatted} (Status: ${status})\n`;
    report += `Período: ${dateStart} a ${dateStop}`;
    if (saldo_restante) {
      report += ` (Saldo restante: ${currency} ${saldo_restante})`;
    }
    report += `\nAlcance: ${reach}`;
    report += `\nImpressões: ${impressions}`;
    report += `\nCliques no Link: ${clicks}`;
    report += `\nCPM: ${currency} ${cpm}`;
    report += `\nCTR: ${ctr}%`;
    report += `\nLeads: ${lead}`;
    report += `\nCusto por Lead: ${currency} ${custo_lead}`;
    report += `\nCompras: ${purchase}`;
    report += `\nCusto por Compra: ${currency} ${custo_purchase}`;

    reports.push({
      json: {
        account_id: accountId,
        report: report
      }
    });
}

return reports;

// Pega os dados dos dois JSONs de entrada
let jsonData1 = $node["[CTX] Client Ad Accounts1"].json["data"];
let jsonData2 = $node["[CTX] Owned Ad Accounts1"].json["data"];

// Cria um array combinado para armazenar os dados de ambos os JSONs
